// Función para formato de moneda
function formatSoles(amount) {
  return Number(amount || 0).toLocaleString('es-PE', {
    style: 'currency',
    currency: 'PEN',
    minimumFractionDigits: 2
  });
}

// Verificar si hay datos de entrada
if (!$input || !$input.all || $input.all().length === 0) {
  const sqlQuery = $node["Postgres1"].parameters?.query || "Consulta no disponible";
  return [{
    json: {
      message: `⚠️ No se recibieron datos de PostgreSQL:\n\n\`${sqlQuery.replace(/\s+/g, ' ').trim()}\``,
      chat_id: $node["Postgres1"].json?.chat_id || 
              $input.all()[0]?.json?.message?.chat?.id
    }
  }];
}

// Obtener todos los items de entrada
const allItems = $input.all();

// Procesar cada item individualmente
const results = [];
for (const item of allItems) {
  if (!item.json) continue;

  // Si es array de resultados (pg_results)
  if (Array.isArray(item.json.pg_results)) {
    for (const result of item.json.pg_results) {
      results.push({
        json: {
          message: `📦 *PAC:* ${result.pac || "N/A"}\n🔢 *OBAC:* ${result.obac || "N/A"}\n📝 *Descripción:* ${result.descripcion || "N/A"}\n🔢 *Proceso:* ${result.tp || "N/A"}\n💰 *Estimado:* ${formatSoles(result.cuantia)}\n📝 *Estado:* ${result.estado || "N/A"}\n🔄 *Situación:* ${result.situacion || "N/A"}`,
          chat_id: result.chat_id || 
                   item.json.chat_id || 
                   $node["Postgres1"].json?.chat_id
        }
      });
    }
  } 
  // Si es un item individual (sin pg_results)
  else if (item.json.pac) {
    results.push({
      json: {
        message: `📦 *PAC:* ${item.json.pac || "N/A"}\n🔢 *OBAC:* ${item.json.obac || "N/A"}\n📝 *Descripción:* ${item.json.descripcion || "N/A"}\n🔢 *Proceso:* ${item.json.tp || "N/A"}\n💰 *Estimado:* ${formatSoles(item.json.cuantia)}\n📝 *Estado:* ${item.json.estado || "N/A"}\n🔄 *Situación:* ${item.json.situacion || "N/A"}`,
        chat_id: item.json.chat_id || 
                 $node["Postgres1"].json?.chat_id
      }
    });
  }
}

// Si no se procesó ningún resultado
if (results.length === 0) {
  const sqlQuery = $node["Postgres1"].parameters?.query || "Consulta no disponible";
  return [{
    json: {
      message: `⚠️ No se encontraron registros válidos para:\n\n\`${sqlQuery.replace(/\s+/g, ' ').trim()}\``,
      chat_id: $node["Postgres1"].json?.chat_id || 
              $input.all()[0]?.json?.message?.chat?.id
    }
  }];
}

// Devolver todos los resultados procesados
return results;

return {
  rowNumber: parseInt($input.all()[0].json.message.text.split(' ')[1])
};

// Obtener el contenido desde el nodo anterior
const rawText = $json["content"] || "";

// Separar el texto en párrafos (asumiendo que hay dos saltos de línea o uno)
const paragraphs = rawText
  .split(/\n{2,}|\r?\n/)
  .map(p => p.trim())
  .filter(p => p.length > 0);

// Crear objeto JSON con claves "marca 1", "marca 2", ...
const result = {};
paragraphs.forEach((p, index) => {
  result[`marca ${index + 1}`] = p;
});

// Devolver el resultado como nuevo item
return [
  {
    json: result
  }
];

// Obtener el texto generado por el AI Agent
let raw = $json["output"];

// Eliminar delimitadores de bloque de código (```json ... ```)
raw = raw.replace(/```json\n?|```/g, "").trim();

// Parsear como JSON
const cleaned = JSON.parse(raw);

// Devolver como objeto n8n
return [
  {
    json: cleaned
  }
];

return {
  rowNumber: parseInt($input.all()[0].json.message.text.split(' ')[1])
};

