// Obtener el contenido desde el nodo anterior
const rawText = $json["content"] || "";

// Separar el texto en párrafos (asumiendo que hay dos saltos de línea o uno)
const paragraphs = rawText
  .split(/\n{2,}|\r?\n/)
  .map(p => p.trim())
  .filter(p => p.length > 0);

// Crear objeto JSON con claves "marca 1", "marca 2", ...
const result = {};
paragraphs.forEach((p, index) => {
  result[`marca ${index + 1}`] = p;
});

// Devolver el resultado como nuevo item
return [
  {
    json: result
  }
];

let raw = $json["output"];

// Eliminar delimitadores de bloque de código
raw = raw.replace(/```json|```/gi, "").trim();

// Intentar extraer el bloque JSON válido
try {
  // Buscar solo el bloque JSON
  const jsonMatch = raw.match(/{[\s\S]*}/);
  if (!jsonMatch) {
    throw new Error("No se encontró un bloque JSON válido.");
  }

  const cleaned = JSON.parse(jsonMatch[0]);

  return [
    {
      json: cleaned
    }
  ];

} catch (error) {
  return [
    {
      json: {
        error: true,
        message: "Error al parsear JSON",
        detalle: error.message,
        contenido: raw
      }
    }
  ];
}

// Obtener las filas del nodo anterior (Google Sheets)
const rows = $input.all().map(item => item.json);

// Guardar estructura para AI Agent
const datos_para_ai = rows;

// Generar HTML para la tabla
let tabla_html = `<table border="1" style="border-collapse: collapse;">`;

// Agregar encabezados
tabla_html += "<tr>";
Object.keys(rows[0]).forEach(key => {
  tabla_html += `<th style="background-color:#f0f0f0; padding:6px;">${key}</th>`;
});
tabla_html += "</tr>";

// Agregar filas
rows.forEach(row => {
  tabla_html += "<tr>";
  Object.values(row).forEach(cell => {
    tabla_html += `<td style="padding:6px;">${cell}</td>`;
  });
  tabla_html += "</tr>";
});

tabla_html += "</table>";

// Devolver salida con ambos datos
return [{
  json: {
    datos_ai: datos_para_ai,
    tabla_html: tabla_html
  }
}];

return {
  rowNumber: parseInt($input.all()[0].json.message.text.split(' ')[1])
};

// Obtener el contenido desde el nodo anterior
const rawText = $json["content"] || "";

// Separar el texto en párrafos (asumiendo que hay dos saltos de línea o uno)
const paragraphs = rawText
  .split(/\n{2,}|\r?\n/)
  .map(p => p.trim())
  .filter(p => p.length > 0);

// Crear objeto JSON con claves "marca 1", "marca 2", ...
const result = {};
paragraphs.forEach((p, index) => {
  result[`marca ${index + 1}`] = p;
});

// Devolver el resultado como nuevo item
return [
  {
    json: result
  }
];

let raw = $json["output"];

try {
  // Limpiar el string primero
  raw = raw.trim()
    .replace(/^\{/, '')
    .replace(/\}$/, '')
    .split('\n')
    .map(line => line.trim())
    .filter(line => line)
    .map(line => {
      const parts = line.split(':');
      const key = parts[0].trim().replace(/"/g, '');
      const value = parts.slice(1).join(':').trim().replace(/,$/, '');
      return `"${key}": "${value.replace(/"/g, '\\"')}"`;
    })
    .join(',\n');

  const jsonStr = `{${raw}}`;
  const cleaned = JSON.parse(jsonStr);

  return [{ json: cleaned }];
} catch (error) {
  return [{
    json: {
      error: true,
      message: "Error al parsear JSON",
      detalle: error.message,
      contenido: raw
    }
  }];
}

// Inicializamos los arreglos
let rubrosRES = [];
let rubrosLP = [];
let rubrosCP = [];
let rubrosCorporativo = [];

// Procesamos todos los registros
for (const item of $input.all()) {
  const record = item.json;
  const rubro = (record['RUBRO (NUMERO)'] || '').toString().toUpperCase();
  const tp = (record.TP || '').toString().toUpperCase();
  const numero = record['N°'];  // puede ser número o string

  const data = {
    "RUBRO (NUMERO)": rubro,
    "N°": numero
  };

  if (rubro === 'CORPORATIVO') {
    rubrosCorporativo.push(data);
  } else {
    if (tp === 'RES') {
      rubrosRES.push(data);
    } else if (tp === 'LP') {
      rubrosLP.push(data);
    } else if (tp === 'CP') {
      rubrosCP.push(data);
    }
  }
}

// Devolvemos ambos: los arreglos y los conteos
return [{
  json: {
    RES: rubrosRES,
    RES_COUNT: rubrosRES.length,

    LP: rubrosLP,
    LP_COUNT: rubrosLP.length,

    CP: rubrosCP,
    CP_COUNT: rubrosCP.length,

    CORPORATIVO: rubrosCorporativo,
    CORPORATIVO_COUNT: rubrosCorporativo.length
  }
}];

