const formatDate = (dateInput) => {
  if (!dateInput) return "dd/mm/aaaa";

  try {
    const date = new Date(dateInput);
    if (isNaN(date.getTime())) return "dd/mm/aaaa";

    return [
      date.getDate().toString().padStart(2, '0'),
      (date.getMonth() + 1).toString().padStart(2, '0'),
      date.getFullYear()
    ].join('/');
  } catch {
