    json: result
  }
];

let raw = $json["output"];

try {
  // Limpiar el string primero
  raw = raw.trim()
    .replace(/^\{/, '')
    .replace(/\}$/, '')
    .split('\n')
    .map(line => line.trim())
    .filter(line => line)
    .map(line => {
      const parts = line.split(':');
      const key = parts[0].trim().replace(/"/g, '');
      let value = parts.slice(1).join(':').trim().replace(/,$/, '');

      // Eliminar comillas al inicio y final del valor si las tiene
      value = value.replace(/^"(.*)"$/, '$1');

      return `"${key}": "${value.replace(/"/g, '\\"')}"`;
    })
    .join(',\n');

  const jsonStr = `{${raw}}`;
  const cleaned = JSON.parse(jsonStr);

  return [{ json: cleaned }];
} catch (error) {
  return [{
    json: {
      error: true,
      message: "Error al parsear JSON",
      detalle: error.message,
      contenido: raw
    }
  }];
}

