  const record = item.json;
  const rubro = (record['RUBRO (NUMERO)'] || '').toString().trim().toUpperCase();
  const tp = (record.TP || '').toString().toUpperCase();
  const numeroRef = record['N° REF'];

  const data = {
    "RUBRO (NUMERO)": rubro,
    "N° REF": numeroRef,
    "TP": tp
  };

  // 1. Filtro estricto para CORPORATIVO (excluye de otros grupos)
  if (rubro.includes('CORPORATIVO')) {
    rubrosCorporativo.push(data);
    continue; // ¡IMPORTANTE! Salta a la siguiente iteración
  }

  // 2. Clasificación normal para no-corporativos
  if (tp === 'RES') {
    rubrosRES.push(data);
  } else if (tp === 'LP') {
    rubrosLP.push(data);
  } else if (tp === 'CP') {
    rubrosCP.push(data);
  }
}

// Devolvemos los datos agrupados
return [{
  json: {
    CORPORATIVO: rubrosCorporativo,
    CORPORATIVO_COUNT: rubrosCorporativo.length,

    RES: rubrosRES,
    RES_COUNT: rubrosRES.length,

    LP: rubrosLP,
    LP_COUNT: rubrosLP.length,

    CP: rubrosCP,
    CP_COUNT: rubrosCP.length,

    // Grupo combinado SOLO LP y CP (sin corporativos)
    LP_CP: [...rubrosLP, ...rubrosCP],
    LP_CP_COUNT: rubrosLP.length + rubrosCP.length
  }
}];

