  if (rubro.includes('CORPORATIVO')) {
    rubrosCorporativo.push(data);
    continue; // ¡IMPORTANTE! Salta a la siguiente iteración
  }

  // 2. Clasificación normal para no-corporativos
  if (tp === 'RES') {
    rubrosRES.push(data);
  } else if (tp === 'LP') {
    rubrosLP.push(data);
  } else if (tp === 'CP') {
    rubrosCP.push(data);
  }
}

// Devolvemos los datos agrupados
return [{
  json: {
    CORPORATIVO: rubrosCorporativo,
