    W: "Mantenimiento mayor",
    X: "Servicios especializados"
  }
];

// Agregar filas dinámicas basadas en los datos de entrada (Sheet Read)
if ($input.first()) {
  const inputData = $input.all();

  inputData.forEach(item => {
    data.push({
