// PREPARAR SOLICITUD - CON REFERENCIAS VARIABLES
const item = $input.first();

// Obtener HTML
const html = item.json?.data || item.json || '';

// Buscar ViewState
let viewState = '';
const match = html.match(/name="javax\.faces\.ViewState"[^>]*value="([^"]*)"/);
if (match && match[1]) viewState = match[1];

if (!viewState) throw new Error('ViewState no encontrado');

// OBTENER CONFIGURACIÓN DEL NODO "Configurar Búsqueda"
let entidad, año, version;

try {
  // Buscar en todos los nodos anteriores
  const allNodes = $input.all();
  for (const node of allNodes) {
    if (node.json && node.json.config) {
      entidad = node.json.config.entidad;
      año = node.json.config.año;
      version = node.json.config.version;
      console.log('✅ Configuración obtenida del nodo anterior');
      break;
    }
  }

  // Si no se encontró, usar valores por defecto
  if (!entidad) {
    entidad = 'AGENCIA DE COMPRAS DE LAS FUERZAS ARMADAS';
    año = '2025';
    version = '3';
    console.log('⚠️ Usando valores por defecto');
  }

} catch (error) {
  // Fallback
  entidad = 'AGENCIA DE COMPRAS DE LAS FUERZAS ARMADAS';
  año = '2025';
  version = '3';
}

return [{
  json: {
    viewState: viewState,
    jfwToken: '',
    cookies: '',
    entidad: entidad,
    año: año,
    version: version,
    mensaje: '✅ Configuración variable cargada correctamente'
  }
}];

// Guardar Excel
