const puppeteer = require('puppeteer');
const fs = require('fs');
const path = require('path');

async function run() {
  const entidad = $json["entidad"];
  const anio = $json["anio"];
  const version = $json["version"];

  const downloadPath = '/home/node/scripts/downloads';

  if (!fs.existsSync(downloadPath)) fs.mkdirSync(downloadPath, { recursive: true });

  const browser = await puppeteer.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-setuid-sandbox']
  });

  const page = await browser.newPage();
  console.log("🌐 Navegando a SEACE...");

  await page.goto('https://prod2.seace.gob.pe/seacebus-uiwd-pub/buscadorPublico/buscadorPublico.xhtml', {
    waitUntil: 'networkidle2'
  });

  // Completar entidad
  await page.waitForSelector('#tbBuscador\\:idFormBuscarProceso\\:nombreEntidad');
  await page.type('#tbBuscador\\:idFormBuscarProceso\\:nombreEntidad', entidad);

  // Esperar y seleccionar año (click y selección manual)
  await page.click('#tbBuscador\\:idFormBuscarProceso\\:anioConvocatoria_label');
  await page.waitForSelector(`#tbBuscador\\:idFormBuscarProceso\\:anioConvocatoria_items li[data-label="${anio}"]`, { visible: true });
  await page.click(`#tbBuscador\\:idFormBuscarProceso\\:anioConvocatoria_items li[data-label="${anio}"]`);

  // Esperar y seleccionar versión
  await page.click('#tbBuscador\\:idFormBuscarProceso\\:versionSeace_label');
  await page.waitForSelector(`#tbBuscador\\:idFormBuscarProceso\\:versionSeace_items li[data-label="${version}"]`, { visible: true });
  await page.click(`#tbBuscador\\:idFormBuscarProceso\\:versionSeace_items li[data-label="${version}"]`);

  // Buscar
  await Promise.all([
    page.click('#tbBuscador\\:idFormBuscarProceso\\:btnBuscarSel'),
    page.waitForNavigation({ waitUntil: 'networkidle2' }),
  ]);

  // Esperar botón exportar
  await page.waitForSelector('#tbBuscador\\:idFormBuscarProceso\\:btnExportar', { timeout: 60000 });

  // Configurar descarga
  const client = await page.target().createCDPSession();
  await client.send('Page.setDownloadBehavior', {
    behavior: 'allow',
    downloadPath,
  });

  // Exportar Excel
  await page.click('#tbBuscador\\:idFormBuscarProceso\\:btnExportar');
  await new Promise(resolve => setTimeout(resolve, 10000));

  const files = fs.readdirSync(downloadPath);
  const excelFile = files.find(f => f.endsWith('.xls') || f.endsWith('.xlsx'));
  if (!excelFile) throw new Error('❌ No se descargó el archivo Excel.');

  const excelPath = path.join(downloadPath, excelFile);
  const data = fs.readFileSync(excelPath);

  await browser.close();

  return [
    {
      json: { mensaje: '✅ Excel descargado correctamente', archivo: excelFile },
      binary: {
        data: {
          data: data.toString('base64'),
          mimeType: 'application/vnd.ms-excel',
          fileName: excelFile,
        },
      },
    },
  ];
}

return run();

