const html = $json.data || $json.body || '';
const vs = html.match(/name=["']javax\.faces\.ViewState["'][^>]*value=["']([^"']+)/);
if (!vs) throw new Error('No se encontró javax.faces.ViewState');
const viewState = vs[1];
const jsession = html.match(/jsessionid=([A-Za-z0-9._-]+)/i);
const cookie = jsession ? `JSESSIONID=${jsession[1]}` : '';
const boton = html.includes('btnBuscarSelToken') ? 'btnBuscarSelToken' : 'btnBuscarSel';
return [{ json: { viewState, cookie, boton, mensaje: `✅ ViewState y cookie listos (${boton})` } }];

const xml = $json.data || $json.body || '';
const m = xml.match(/<update[^>]*ViewState[^>]*>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/update>/i);
return [{ json: { nuevoViewState: m ? m[1].trim() : null, xmlPreview: xml.slice(0, 400) } }];

const xml = $json.data || $json.body || '';
if (/No se encontraron Datos/i.test(xml)) {
  return [{ json: { tieneDatos: false, año: $('Configurar búsqueda').item.json.config.año, mensaje: '⚠️ Sin datos, se probará año anterior', xmlPreview: xml.slice(0, 300) } }];
}
return [{ json: { tieneDatos: true, data: xml } }];

const xml = $json.data || $json.body || '';
const tbody = xml.match(/<tbody[\s\S]*?<\/tbody>/i);
if (!tbody) return [{ json: { tieneDatos: false, mensaje: '❌ No se encontró tabla final' } }];
const rows = [...tbody[0].matchAll(/<tr[\s\S]*?<\/tr>/g)];
if (!rows.length) return [{ json: { tieneDatos: false, mensaje: '⚠️ Tabla vacía' } }];
const limpiar = t => t.replace(/<[^>]+>/g, '').trim();
const primera = [...rows[0][0].matchAll(/<td[\s\S]*?<\/td>/g)].map(m => limpiar(m[0]));
return [{ json: { tieneDatos: true, totalFilas: rows.length, ejemplo: primera, mensaje: `✅ ${rows.length} filas detectadas` } }];

// CONFIGURACIÓN Y PROCESAMIENTO DE MENSAJE TELEGRAM
const message = $input.first().json.message;
const chatId = message.chat.id;
const textoUsuario = message.text;

// Palabras clave a buscar (configurables)
const config = {
  palabrasClave: ['consultoría', 'software', 'tecnología', 'informática', 'seguridad', 'sistema', 'digital', 'TI', 'tic'],
  añosBusqueda: ['2025', '2024'],
  entidadDefault: 'AGENCIA DE COMPRAS DE LAS FUERZAS ARMADAS'
};

// Extraer palabras clave del mensaje
const palabrasBuscar = textoUsuario.toLowerCase().split(' ').filter(palabra => 
  palabra.length > 3 && !['buscar', 'consultar', 'procesos', 'seace'].includes(palabra)
);

// Si no hay palabras específicas, usar las configuradas
const palabrasFinales = palabrasBuscar.length > 0 ? palabrasBuscar : config.palabrasClave;

return [{
  json: {
    chatId: chatId,
    textoUsuario: textoUsuario,
    palabrasBusqueda: palabrasFinales,
    añosBusqueda: config.añosBusqueda,
    entidad: config.entidadDefault,
    timestamp: new Date().toISOString(),
    mensaje: `🔍 Búsqueda configurada: ${palabrasFinales.join(', ')}`
  }
}];

// EXTRAER Y FILTRAR PROCESOS POR PALABRAS CLAVE
const item = $input.first();
const tablaHtml = item.json.tabla_resultados;
const palabrasBusqueda = $('Procesar Mensaje Telegram').item.json.palabrasBusqueda;

console.log('=== BUSCANDO PALABRAS:', palabrasBusqueda);

if (!tablaHtml) {
  return [{
    json: {
      procesosEncontrados: [],
      mensaje: '❌ No se pudo acceder a la tabla de SEACE. Verifica que hayas realizado la búsqueda manual primero.',
      totalEncontrados: 0
    }
  }];
}

// Extraer todas las filas de procesos
const procesos = [];
const regexFila = /<tr[^>]*class="[^"]*ui-widget-content[^"]*"[^>]*>([\s\S]*?)<\/tr>/g;
let filaMatch;

while ((filaMatch = regexFila.exec(tablaHtml)) !== null) {
  const filaHtml = filaMatch[1];
  const celdas = filaHtml.match(/<td[^>]*>([\s\S]*?)<\/td>/g) || [];

  if (celdas.length >= 10) {
    const proceso = {
      numero: limpiarTexto(extraerContenido(celdas[0])),
      entidad: limpiarTexto(extraerContenido(celdas[1])),
      fecha_publicacion: limpiarTexto(extraerContenido(celdas[2])),
      nomenclatura: limpiarTexto(extraerContenido(celdas[3])),
      objeto_contratacion: limpiarTexto(extraerContenido(celdas[5])),
      descripcion_objeto: limpiarTexto(extraerContenido(celdas[6])),
      codigo_snip: limpiarTexto(extraerContenido(celdas[7])),
      codigo_inversion: limpiarTexto(extraerContenido(celdas[8])),
      valor_referencial: limpiarTexto(extraerContenido(celdas[9])),
      moneda: limpiarTexto(extraerContenido(celdas[10])),
      version_seace: limpiarTexto(extraerContenido(celdas[11]))
    };

    // Solo agregar procesos válidos
    if (proceso.nomenclatura && proceso.nomenclatura !== 'No se encontraron Datos') {
      procesos.push(proceso);
    }
  }
}

// FILTRAR por palabras clave
const procesosFiltrados = procesos.filter(proceso => {
  const textoBusqueda = `${proceso.descripcion_objeto} ${proceso.objeto_contratacion} ${proceso.nomenclatura}`.toLowerCase();

  return palabrasBusqueda.some(palabra => 
    textoBusqueda.includes(palabra.toLowerCase())
  );
});

// Funciones auxiliares
function extraerContenido(html) {
  return html ? html.replace(/<[^>]*>/g, '').trim() : '';
}

function limpiarTexto(texto) {
  return texto ? texto.replace(/\s+/g, ' ').trim() : '';
}

return [{
  json: {
    procesosEncontrados: procesosFiltrados,
    totalProcesos: procesos.length,
    totalEncontrados: procesosFiltrados.length,
    palabrasBuscadas: palabrasBusqueda,
    mensaje: procesosFiltrados.length > 0 ? 
      `✅ Encontrados ${procesosFiltrados.length} procesos de ${procesos.length} totales` :
      `❌ No se encontraron procesos con las palabras: ${palabrasBusqueda.join(', ')}`,
    timestamp: new Date().toISOString()
  }
}];

// PREPARAR RESPUESTA PARA TELEGRAM
const item = $input.first();
const procesos = $('Filtrar Procesos').item.json.procesosEncontrados;
const totalEncontrados = $('Filtrar Procesos').item.json.totalEncontrados;
const palabrasBuscadas = $('Filtrar Procesos').item.json.palabrasBuscadas;
const chatId = $('Procesar Mensaje Telegram').item.json.chatId;

let mensajeTelegram = '';

if (totalEncontrados > 0) {
  mensajeTelegram = `🎯 *SEACE BOT - Resultados*\n\n`;
  mensajeTelegram += `🔍 *Palabras buscadas:* ${palabrasBuscadas.join(', ')}\n`;
  mensajeTelegram += `📊 *Procesos encontrados:* ${totalEncontrados}\n\n`;

  // Mostrar máximo 5 procesos para no saturar
  procesos.slice(0, 5).forEach((proceso, index) => {
    mensajeTelegram += `*${index + 1}. ${proceso.nomenclatura}*\n`;
    mensajeTelegram += `🏢 ${proceso.entidad}\n`;
    mensajeTelegram += `📝 ${proceso.descripcion_objeto.substring(0, 100)}...\n`;
    mensajeTelegram += `💰 ${proceso.valor_referencial} ${proceso.moneda}\n`;
    mensajeTelegram += `📅 ${proceso.fecha_publicacion}\n\n`;
  });

  if (totalEncontrados > 5) {
    mensajeTelegram += `📋 _+${totalEncontrados - 5} procesos más en Google Sheets_\n`;
  }

  mensajeTelegram += `✅ *Guardado en Google Sheets*`;

} else {
  mensajeTelegram = `❌ *SEACE BOT - Sin Resultados*\n\n`;
  mensajeTelegram += `🔍 *Palabras buscadas:* ${palabrasBuscadas.join(', ')}\n`;
