function formatSoles(amount) {
  return Number(amount || 0).toLocaleString('es-PE', {
    style: 'currency',
    currency: 'PEN',
    minimumFractionDigits: 2
  });
}

// Función para escapar caracteres especiales en MarkdownV2 de Telegram
function escapeMarkdownV2(text) {
  if (!text || typeof text !== 'string') return text;

  const specialChars = ['_', '*', '[', ']', '(', ')', '~', '`', '>', '#', '+', '-', '=', '|', '{', '}', '.', '!'];

  let escapedText = text;
  specialChars.forEach(char => {
    escapedText = escapedText.replace(new RegExp(`\\${char}`, 'g'), `\\${char}`);
  });

  return escapedText;
}

// Función para crear mensaje formateado
function createMessage(data) {
  return `📦 *PAC:* ${escapeMarkdownV2(data.pac) || "N/A"}
🔢 *OBAC:* ${escapeMarkdownV2(data.obac) || "N/A"}
📝 *Descripción:* ${escapeMarkdownV2(data.descripcion) || "N/A"}
🔢 *Proceso:* ${escapeMarkdownV2(data.tp) || "N/A"}
💰 *Estimado:* ${formatSoles(data.cuantia)}
📝 *Estado:* ${escapeMarkdownV2(data.estado) || "N/A"}
🔄 *Situación:* ${escapeMarkdownV2(data.situacion) || "N/A"}`;
}

