html += '            <tr><td>Contrapartidas (10%)</td><td>' + getVal(datos, 'pts_contrapartida') + '</td><td>10%</td><td>' + (getVal(datos, 'pts_contrapartida') * 1).toFixed(1) + '</td><td>' + getVal(datos, 'porcentaje_contrapartida') + '</td></tr>\n';
