// VI. PUNTAJE TOTAL Y RESULTADO (HORIZONTAL)
html += '    <div class="section">\n';
html += '        <h2>VI. PUNTAJE TOTAL Y RESULTADO</h2>\n';
html += '        <div class="resultado-horizontal">\n';
html += '            <div><strong>Puntaje Total:</strong> ' + getVal(datos, 'puntaje_final_total') + '</div>\n';
