html += '            <li>' + getVal(datos, 'obs_subsanacion_2') + '</li>\n';
html += '        </ul>\n';
html += '    </div>\n';

html += '</body>\n';
html += '</html>';

// Devolver el HTML y también los valores clave para Supabase
return {
    html_content: html,
    datos_originales: datos,
    puntaje_final: datos.puntaje_final_total || 0,
    resultado: datos.resultado_evaluacion || ''
};
